import { defineTool, getConfig } from '@opentabs-dev/plugin-sdk';
import { z } from 'zod';

export const sdkGetConfig = defineTool({
  name: 'sdk_get_config',
  description: 'Tests getConfig — reads a plugin config value by key',
  input: z.object({ key: z.string().describe('Config key to read') }),
  output: z.object({ key: z.string(), value: z.union([z.string(), z.number(), z.boolean()]).nullable() }),
  async handle(params) {
    const value = getConfig(params.key);
    return { key: params.key, value: value ?? null };
  },
});
```

